#include <stdio.h>
#include <string.h>
#include <ctype.h> // For isalnum and tolower

#define MAX_INPUT_LENGTH 101 // Max 100 chars + null terminator

int main() {
    char input_string[MAX_INPUT_LENGTH];
    char filtered_string[MAX_INPUT_LENGTH]; // To store only alphanumeric, lowercase chars
    int i, j;
    int len_filtered;
    int is_palindrome = 1; // Assume it's a palindrome until proven otherwise

    // Read the input line
    if (fgets(input_string, sizeof(input_string), stdin) == NULL) {
        return 1; // Error reading input
    }

    // Remove the trailing newline character if present
    input_string[strcspn(input_string, "\n")] = 0;

    // Filter alphanumeric characters and convert to lowercase
    j = 0;
    for (i = 0; input_string[i] != '\0'; i++) {
        if (isalnum((unsigned char)input_string[i])) {
            filtered_string[j] = tolower((unsigned char)input_string[i]);
            j++;
        }
    }
    filtered_string[j] = '\0'; // Null-terminate the filtered string

    len_filtered = strlen(filtered_string);

    // Check if the filtered string is a palindrome
    // An empty string or a single-character string is considered a palindrome
    if (len_filtered <= 1) {
        is_palindrome = 1;
    } else {
        int left = 0;
        int right = len_filtered - 1;
        while (left < right) {
            if (filtered_string[left] != filtered_string[right]) {
                is_palindrome = 0; // Mismatch found, not a palindrome
                break;
            }
            left++;
            right--;
        }
    }

    // Print the result
    if (is_palindrome) {
        printf("The string is a palindrome.\n");
    } else {
        printf("The string is NOT a palindrome.\n");
    }

    return 0;
}
